    31→// Calculate next review using FSRS-5
    32→function fsrs5Schedule(card: Flashcard, rating: Rating): Partial<Flashcard> {
    33→  const ratingMap: Record<Rating, number> = { again: 1, hard: 2, good: 3, easy: 4 };
    34→  const r = ratingMap[rating];
    35→
    36→  let newState: CardState = card.state;
    37→  let newStability = card.stability;
    38→  let newDifficulty = card.difficulty;
    39→  let newReps = card.reps;
    40→  let newLapses = card.lapses;
    41→  let scheduledDays = 1;
    42→
    43→  if (card.state === 'new') {
    44→    // First review
    45→    newState = 'learning';
    46→    newStability = FSRS_PARAMS.w[r - 1];
    47→    newDifficulty = FSRS_PARAMS.w[4] - Math.exp(FSRS_PARAMS.w[5] * (r - 3)) + 1;
    48→    newDifficulty = Math.max(1, Math.min(10, newDifficulty));
    49→    newReps = 1;
    50→  } else if (rating === 'again') {
    51→    // Lapse
    52→    newState = 'relearning';
    53→    newLapses = card.lapses + 1;
    54→    newStability = Math.max(0.1, card.stability * FSRS_PARAMS.w[11]);
    55→  } else {
    56→    // Successful review
    57→    newState = 'review';
    58→    newReps = card.reps + 1;
    59→
    60→    // Update difficulty
    61→    const deltaDifficulty = -FSRS_PARAMS.w[6] * (r - 3);
    62→    newDifficulty = Math.max(1, Math.min(10, card.difficulty + deltaDifficulty));
    63→
    64→    // Update stability
    65→    const retrievability = Math.pow(1 + card.elapsedDays / (9 * card.stability), -1);
    66→    const stabilityIncrease = Math.exp(FSRS_PARAMS.w[8]) *
    67→      (11 - newDifficulty) *
    68→      Math.pow(card.stability, -FSRS_PARAMS.w[9]) *
    69→      (Math.exp((1 - retrievability) * FSRS_PARAMS.w[10]) - 1);
    70→
    71→    if (rating === 'hard') {
    72→      newStability = card.stability * (1 + stabilityIncrease * FSRS_PARAMS.w[15]);
    73→    } else if (rating === 'easy') {
    74→      newStability = card.stability * (1 + stabilityIncrease * FSRS_PARAMS.w[16]);
    75→    } else {
    76→      newStability = card.stability * (1 + stabilityIncrease);
    77→    }
    78→  }
    79→
    80→  // Calculate interval
    81→  const requestedRetention = FSRS_PARAMS.requestRetention;
    82→  scheduledDays = Math.round(
    83→    9 * newStability * (1 / requestedRetention - 1)
    84→  );
    85→  scheduledDays = Math.max(1, Math.min(scheduledDays, FSRS_PARAMS.maximumInterval));
    86→
    87→  return {
    88→    state: newState,
    89→    stability: newStability,
    90→    difficulty: newDifficulty,
    91→    reps: newReps,
    92→    lapses: newLapses,
    93→    scheduledDays,
    94→    elapsedDays: 0,
    95→    lastReview: new Date(),
    96→    nextReview: new Date(Date.now() + scheduledDays * 24 * 60 * 60 * 1000),
    97→  };
    98→}
