   152→          </div>
   153→          <div className="flex-1 min-w-0">
   154→            <div className="flex items-baseline gap-2 text-sm">
   155→              <span className="font-bold text-slate-900 dark:text-white">Lv.{level}</span>
   156→              <span className="text-xs text-slate-500">{xpInLevel}/{xpNeeded} XP</span>
